from flask import Flask, request, Response, jsonify
from prometheus_client import Counter, Histogram, Gauge, generate_latest, CONTENT_TYPE_LATEST
import time

app = Flask(__name__)

REQUEST_COUNT = Counter(
    "http_requests_total",
    "Total HTTP requests",
    ["method", "endpoint", "status_code", "user_id", "api_key"]
)

REQUEST_LATENCY = Histogram(
    "http_request_duration_seconds",
    "HTTP request latency in seconds",
    ["method", "endpoint", "user_id", "api_key"]
)

IN_PROGRESS = Gauge(
    "http_requests_in_progress",
    "Number of HTTP requests in progress",
    ["method", "endpoint", "user_id", "api_key"]
)

REQUEST_BODY_SIZE = Histogram(
    "http_request_body_size_bytes",
    "HTTP request body size in bytes",
    ["method", "endpoint", "user_id", "api_key"]
)

REQUEST_BODY_INFO = Counter(
    "http_request_body_total",
    "HTTP requests with request body details",
    ["method", "endpoint", "user_id", "api_key", "request_body"]
)

@app.before_request
def before_request():
    request._start_time = time.time()
    request._user_id = request.headers.get("X-User-Id", "anonymous")
    request._api_key = request.headers.get("X-API-Key", "missing")
    request._endpoint = request.endpoint or request.path
    IN_PROGRESS.labels(
        method=request.method,
        endpoint=request._endpoint,
        user_id=request._user_id,
        api_key=request._api_key
    ).inc()

@app.after_request
def after_request(response):
    duration = time.time() - getattr(request, "_start_time", time.time())
    user_id = getattr(request, "_user_id", "anonymous")
    api_key = getattr(request, "_api_key", "missing")
    endpoint = getattr(request, "_endpoint", request.path)

    REQUEST_COUNT.labels(
        method=request.method,
        endpoint=endpoint,
        status_code=str(response.status_code),
        user_id=user_id,
        api_key=api_key
    ).inc()

    REQUEST_LATENCY.labels(
        method=request.method,
        endpoint=endpoint,
        user_id=user_id,
        api_key=api_key
    ).observe(duration)

    body = request.get_data(cache=True, as_text=True) or ""
    REQUEST_BODY_SIZE.labels(
        method=request.method,
        endpoint=endpoint,
        user_id=user_id,
        api_key=api_key
    ).observe(len(body.encode("utf-8")))

    REQUEST_BODY_INFO.labels(
        method=request.method,
        endpoint=endpoint,
        user_id=user_id,
        api_key=api_key,
        request_body=body
    ).inc()

    IN_PROGRESS.labels(
        method=request.method,
        endpoint=endpoint,
        user_id=user_id,
        api_key=api_key
    ).dec()

    return response

@app.route("/metrics")
def metrics():
    return Response(generate_latest(), mimetype=CONTENT_TYPE_LATEST)

@app.route("/health")
def health():
    return jsonify({"status": "ok"})

@app.route("/api/echo", methods=["POST"])
def echo():
    payload = request.get_json(silent=True)
    return jsonify({
        "user_id": request.headers.get("X-User-Id"),
        "api_key": request.headers.get("X-API-Key"),
        "body": payload if payload is not None else request.get_data(as_text=True)
    })

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)